contracts/lib/Merkle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title Merkle
/// @notice Binary Merkle proof verification over keccak256. Pairs are hashed
///         in order — if the leaf is at an even index its sibling concatenates
///         to the right; at an odd index, to the left. This matches the tree
///         construction used by the indexer (`buildMerkleTree` in
///         `indexer/src/calculators/merkle.ts`).
library Merkle {
    /// @notice Verify that `leaf` is included in the Merkle tree whose root is
    ///         `root` at position `leafIndex`, given the sibling-hash `proof`.
    /// @dev    Cost is roughly `proof.length × 200` gas (one keccak per level).
    function verify(bytes32 root, bytes32 leaf, bytes32[] memory proof, uint32 leafIndex)
        internal
        pure
        returns (bool)
    {
        bytes32 computed = leaf;
        uint256 index = leafIndex;
        for (uint256 i = 0; i < proof.length; i++) {
            bytes32 sibling = proof[i];
            if (index % 2 == 0) {
                computed = keccak256(abi.encodePacked(computed, sibling));
            } else {
                computed = keccak256(abi.encodePacked(sibling, computed));
            }
            index = index / 2;
        }
        return computed == root;
    }
}

contracts/lib/PopId.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title PopId
/// @notice Derives a `bytes32` popId directly from an EVM address.
///
/// In the full PolkaCredit design, popId comes from the Polkadot PoP primitive
/// (DIM1 / DIM2). For this MVP we short-circuit identity: every EVM address is
/// treated as a PoP-verified human, and popId is a left-padded cast of the
/// address. This keeps the contracts compatible with the real PoP primitive
/// later — the only thing that changes is how popId is produced.
library PopId {
    /// @notice Convert an EVM address into a canonical bytes32 popId.
    /// @dev    `bytes32(uint256(uint160(addr)))` pads the 20-byte address into
    ///         the low 20 bytes of a 32-byte word; the upper 12 bytes are zero.
    function fromAddress(address addr) internal pure returns (bytes32) {
        return bytes32(uint256(uint160(addr)));
    }
}

contracts/lib/ScoreMath.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title ScoreMath
/// @notice On-chain reference implementation of the points → score mapping.
/// @dev Matches `computeScore` in `indexer/src/calculators/scoreCalculator.ts`.
///      Piecewise linear: 0→0, 50→100, 100→200, 250→500, 500→850.
library ScoreMath {
    uint64 internal constant MAX_SCORE = 850;

    function computeScore(int64 totalPoints) internal pure returns (uint64) {
        if (totalPoints <= 0) return 0;
        if (totalPoints >= 500) return MAX_SCORE;

        uint64 p = uint64(totalPoints);
        if (p < 50) return (p * 100) / 50;
        if (p < 100) return 100 + ((p - 50) * 100) / 50;
        if (p < 250) return 200 + ((p - 100) * 300) / 150;
        return 500 + ((p - 250) * 350) / 250;
    }
}

