// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title MockStablecoin
/// @notice Minimal ERC-20 used to stand in for USDC or a Polkadot-native
///         stablecoin during local testing and testnet deployment.
contract MockStablecoin {
    string public name = "Mock USD";
    string public symbol = "mUSD";
    uint8 public constant decimals = 18;

    uint256 public totalSupply;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    function mint(address to, uint256 amount) external {
        totalSupply += amount;
        balanceOf[to] += amount;
        emit Transfer(address(0), to, amount);
    }

    function transfer(address to, uint256 amount) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        uint256 allowed = allowance[from][msg.sender];
        require(allowed >= amount, "MockStablecoin: allowance");
        if (allowed != type(uint256).max) {
            allowance[from][msg.sender] = allowed - amount;
        }
        _transfer(from, to, amount);
        return true;
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(balanceOf[from] >= amount, "MockStablecoin: balance");
        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        emit Transfer(from, to, amount);
    }
}

contracts/PointsLedger.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IPointsLedger} from "./interfaces/IPointsLedger.sol";

/// @title PointsLedger
/// @notice Soulbound, per-PoP points accounting. Mint and burn only.
/// @dev All mutations go through authorized contracts (VouchRegistry,
///      ScoreRegistry) or the Indexer. Points are non-transferable.
contract PointsLedger is IPointsLedger {
    struct PointEvent {
        int64 amount; // positive = mint, negative = burn, 0 = marker
        uint64 timestamp; // block number
        uint64 relatedVouchId; // 0 if none
        string reason;
    }

    address public admin;

    /// @notice Addresses allowed to mint/burn/lock. Typically VouchRegistry,
    /// ScoreRegistry, and the indexer signer.
    mapping(address => bool) public authorized;

    mapping(bytes32 => PointsBalance) private _balances;
    mapping(bytes32 => PointEvent[]) private _history;

    /// @notice Locked points per (popId, vouchId). Sum is mirrored in balance.locked.
    mapping(bytes32 => mapping(uint64 => uint64)) public lockedPoints;

    event PointsMinted(bytes32 indexed popId, uint64 amount, string reason);
    event PointsBurned(bytes32 indexed popId, uint64 amount, string reason);
    event PointsLocked(bytes32 indexed popId, uint64 amount, uint64 indexed vouchId);
    event PointsUnlocked(bytes32 indexed popId, uint64 amount, uint64 indexed vouchId);
    event AuthorizedSet(address indexed who, bool enabled);

    modifier onlyAdmin() {
        require(msg.sender == admin, "PointsLedger: not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(authorized[msg.sender], "PointsLedger: not authorized");
        _;
    }

    constructor(address _admin) {
        require(_admin != address(0), "PointsLedger: zero admin");
        admin = _admin;
    }

    function setAuthorized(address who, bool enabled) external onlyAdmin {
        authorized[who] = enabled;
        emit AuthorizedSet(who, enabled);
    }

    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "PointsLedger: zero admin");
        admin = newAdmin;
    }

    // ─────────────────────── Core mint / burn ───────────────────────

    function mintPoints(bytes32 popId, uint64 amount, string calldata reason) external onlyAuthorized {
        require(popId != bytes32(0), "PointsLedger: zero popId");
        require(amount > 0, "PointsLedger: zero amount");

        PointsBalance storage b = _balances[popId];
        b.total += int64(amount);
        b.earned += amount;
        b.available += int64(amount);
        b.lastUpdated = uint64(block.number);

        _history[popId].push(
            PointEvent({amount: int64(amount), timestamp: uint64(block.number), relatedVouchId: 0, reason: reason})
        );
        emit PointsMinted(popId, amount, reason);
    }

    function burnPoints(bytes32 popId, uint64 amount, string calldata reason) external onlyAuthorized {
        require(popId != bytes32(0), "PointsLedger: zero popId");
        require(amount > 0, "PointsLedger: zero amount");

        PointsBalance storage b = _balances[popId];
        b.total -= int64(amount);
        b.burned += amount;
        b.available -= int64(amount);
        b.lastUpdated = uint64(block.number);

        _history[popId].push(
            PointEvent({amount: -int64(amount), timestamp: uint64(block.number), relatedVouchId: 0, reason: reason})
        );
        emit PointsBurned(popId, amount, reason);
    }

    // ─────────────────────── Vouch lock / unlock ───────────────────────

    function lockPoints(bytes32 popId, uint64 amount, uint64 vouchId) external onlyAuthorized {
        require(popId != bytes32(0), "PointsLedger: zero popId");
        require(vouchId != 0, "PointsLedger: zero vouchId");
        PointsBalance storage b = _balances[popId];
        require(b.available >= int64(amount), "PointsLedger: insufficient available");

        b.locked += amount;
        b.available -= int64(amount);
        b.lastUpdated = uint64(block.number);

        lockedPoints[popId][vouchId] += amount;
        emit PointsLocked(popId, amount, vouchId);
    }

    function unlockPoints(bytes32 popId, uint64 amount, uint64 vouchId) external onlyAuthorized {
        require(lockedPoints[popId][vouchId] >= amount, "PointsLedger: not enough locked");

        PointsBalance storage b = _balances[popId];
        b.locked -= amount;
        b.available += int64(amount);
        b.lastUpdated = uint64(block.number);

        lockedPoints[popId][vouchId] -= amount;
        emit PointsUnlocked(popId, amount, vouchId);
    }

    /// @notice Burn `amount` points. The locked-for-vouchId portion is burned
    /// first; if amount > locked, the excess is burned from the available balance
    /// (this is the "penalty" mechanic).
    function burnLockedPoints(bytes32 popId, uint64 amount, uint64 vouchId) external onlyAuthorized {
        PointsBalance storage b = _balances[popId];
        uint64 currentLocked = lockedPoints[popId][vouchId];
        uint64 lockedPortion = amount > currentLocked ? currentLocked : amount;

        if (lockedPortion > 0) {
            b.locked -= lockedPortion;
            lockedPoints[popId][vouchId] -= lockedPortion;
        }

        b.total -= int64(amount);
        b.burned += amount;
        if (amount > lockedPortion) {
            b.available -= int64(amount - lockedPortion);
        }
        b.lastUpdated = uint64(block.number);

        _history[popId].push(
            PointEvent({
                amount: -int64(amount),
                timestamp: uint64(block.number),
                relatedVouchId: vouchId,
                reason: "vouch_penalty"
            })
        );
        emit PointsBurned(popId, amount, "vouch_penalty");
    }

    // ─────────────────────── Views ───────────────────────

    function getBalance(bytes32 popId) external view returns (PointsBalance memory) {
        return _balances[popId];
    }

    function historyLength(bytes32 popId) external view returns (uint256) {
        return _history[popId].length;
    }

    function historyAt(bytes32 popId, uint256 idx) external view returns (PointEvent memory) {
        return _history[popId][idx];
    }

    /// @notice Sum positive point events for a popId within [fromBlock, toBlock].
    /// Skips events labelled "vouched_for" — only self-earned points count.
    /// O(history length); keep windows short or paginate off-chain.
    function getPointsEarnedInWindow(bytes32 popId, uint64 fromBlock, uint64 toBlock) external view returns (uint64) {
        bytes32 vouchedForHash = keccak256(bytes("vouched_for"));
        uint64 total = 0;
        PointEvent[] storage hist = _history[popId];
        for (uint256 i = 0; i < hist.length; i++) {
            PointEvent storage e = hist[i];
            if (e.timestamp < fromBlock || e.timestamp > toBlock) continue;
            if (e.amount <= 0) continue;
            if (keccak256(bytes(e.reason)) == vouchedForHash) continue;
            total += uint64(e.amount);
        }
        return total;
    }
}

contracts/ScoreRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IScoreRegistry} from "./interfaces/IScoreRegistry.sol";
import {ScoreMath} from "./lib/ScoreMath.sol";

/// @title ScoreRegistry (optimistic)
/// @notice Optimistic, Merkle-committed score lifecycle.
///
///   propose → (24-h challenge window) → finalize
///            ↘ dispute → resolveDispute → {Finalized | Rejected}
///
/// External consumers read only *finalized* scores. Pending proposals are
/// visible so independent verifiers can challenge them.
contract ScoreRegistry is IScoreRegistry {
    struct FinalizedScore {
        uint64 score;            // 0..850
        int64 totalPoints;       // snapshot at computation time
        bytes32 eventsRoot;      // Merkle root of events used
        uint64 sourceBlockHeight;
        uint64 finalizedAt;      // block when finalized
        uint64 proposalId;       // produced by which proposal
    }

    /// @notice ~24 hours at 12s/block on Polkadot.
    uint64 public constant CHALLENGE_WINDOW = 7200;

    /// @notice ~6 hours; a proposal can be superseded only after this long.
    uint64 public constant MIN_PROPOSAL_INTERVAL = 1800;

    uint64 public constant MAX_SCORE = 850;

    address public admin;
    address public indexer;
    address public disputeResolver;

    uint64 public nextProposalId = 1;

    mapping(bytes32 => FinalizedScore) private _finalized;
    /// @notice Current pending proposal per popId. A popId can have at most
    ///         one Pending or Disputed proposal at a time.
    mapping(bytes32 => ScoreProposal) private _pending;
    /// @notice Full proposal history, indexed by on-chain proposal id.
    mapping(uint64 => ScoreProposal) private _proposals;

    event ScoreProposed(
        uint64 indexed proposalId,
        bytes32 indexed popId,
        uint64 score,
        int64 totalPoints,
        bytes32 eventsRoot,
        uint32 eventCount,
        uint64 sourceBlockHeight,
        uint16 algorithmVersion,
        uint64 proposedAt
    );
    event ScoreFinalized(
        uint64 indexed proposalId,
        bytes32 indexed popId,
        uint64 score,
        uint64 finalizedAt
    );
    event ScoreDisputed(uint64 indexed proposalId, bytes32 indexed popId, uint64 disputeId);
    event ScoreCorrected(bytes32 indexed popId, uint64 oldScore, uint64 correctedScore);
    event ProposalRejected(uint64 indexed proposalId, bytes32 indexed popId);
    event ProposalSuperseded(uint64 indexed proposalId, bytes32 indexed popId);

    event IndexerSet(address indexed indexer);
    event DisputeResolverSet(address indexed resolver);

    modifier onlyAdmin() {
        require(msg.sender == admin, "ScoreRegistry: not admin");
        _;
    }

    modifier onlyIndexer() {
        require(msg.sender == indexer, "ScoreRegistry: not indexer");
        _;
    }

    modifier onlyDisputeResolver() {
        require(msg.sender == disputeResolver, "ScoreRegistry: not dispute resolver");
        _;
    }

    constructor(address _admin, address _indexer) {
        require(_admin != address(0), "ScoreRegistry: zero admin");
        require(_indexer != address(0), "ScoreRegistry: zero indexer");
        admin = _admin;
        indexer = _indexer;
    }

    function setIndexer(address newIndexer) external onlyAdmin {
        require(newIndexer != address(0), "ScoreRegistry: zero indexer");
        indexer = newIndexer;
        emit IndexerSet(newIndexer);
    }

    function setDisputeResolver(address newResolver) external onlyAdmin {
        require(newResolver != address(0), "ScoreRegistry: zero resolver");
        disputeResolver = newResolver;
        emit DisputeResolverSet(newResolver);
    }

    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "ScoreRegistry: zero admin");
        admin = newAdmin;
    }

    // ─────────────────────── Proposal lifecycle ───────────────────────

    function proposeScore(
        bytes32 popId,
        uint64 score,
        int64 totalPoints,
        bytes32 eventsRoot,
        uint32 eventCount,
        uint64 sourceBlockHeight,
        uint16 algorithmVersion
    ) external onlyIndexer returns (uint64) {
        require(popId != bytes32(0), "ScoreRegistry: zero popId");
        require(score <= MAX_SCORE, "ScoreRegistry: score > max");
        require(sourceBlockHeight <= block.number, "ScoreRegistry: future source");

        ScoreProposal storage cur = _pending[popId];
        if (cur.status == ProposalStatus.Pending) {
            // A pending proposal can only be replaced after MIN_PROPOSAL_INTERVAL
            // to prevent the indexer from re-proposing to dodge a challenge.
            require(
                block.number >= cur.proposedAt + MIN_PROPOSAL_INTERVAL,
                "ScoreRegistry: too soon"
            );
            cur.status = ProposalStatus.Superseded;
            _proposals[cur.id].status = ProposalStatus.Superseded;
            emit ProposalSuperseded(cur.id, popId);
        } else if (cur.status == ProposalStatus.Disputed) {
            revert("ScoreRegistry: dispute pending");
        }

        uint64 pid = nextProposalId++;
        ScoreProposal memory p = ScoreProposal({
            id: pid,
            popId: popId,
            score: score,
            totalPoints: totalPoints,
            eventsRoot: eventsRoot,
            eventCount: eventCount,
            sourceBlockHeight: sourceBlockHeight,
            algorithmVersion: algorithmVersion,
            proposedAt: uint64(block.number),
            proposer: msg.sender,
            status: ProposalStatus.Pending
        });
        _pending[popId] = p;
        _proposals[pid] = p;

        emit ScoreProposed(
            pid,
            popId,
            score,
            totalPoints,
            eventsRoot,
            eventCount,
            sourceBlockHeight,
            algorithmVersion,
            uint64(block.number)
        );
        return pid;
    }

    function finalizeScore(bytes32 popId) external {
        ScoreProposal storage p = _pending[popId];
        require(p.status == ProposalStatus.Pending, "ScoreRegistry: not pending");
        require(block.number >= p.proposedAt + CHALLENGE_WINDOW, "ScoreRegistry: window open");

        p.status = ProposalStatus.Finalized;
        _proposals[p.id].status = ProposalStatus.Finalized;

        _finalized[popId] = FinalizedScore({
            score: p.score,
            totalPoints: p.totalPoints,
            eventsRoot: p.eventsRoot,
            sourceBlockHeight: p.sourceBlockHeight,
            finalizedAt: uint64(block.number),
            proposalId: p.id
        });

        emit ScoreFinalized(p.id, popId, p.score, uint64(block.number));

        // Clear the pending slot so a fresh proposal may be accepted.
        delete _pending[popId];
    }

    // ─────────────────────── DisputeResolver hooks ───────────────────────

    function markDisputed(bytes32 popId, uint64 disputeId) external onlyDisputeResolver {
        ScoreProposal storage p = _pending[popId];
        require(p.status == ProposalStatus.Pending, "ScoreRegistry: not pending");
        require(
            block.number < p.proposedAt + CHALLENGE_WINDOW,
            "ScoreRegistry: window closed"
        );
        p.status = ProposalStatus.Disputed;
        _proposals[p.id].status = ProposalStatus.Disputed;
        emit ScoreDisputed(p.id, popId, disputeId);
    }

    function resolveDispute(
        bytes32 popId,
        bool disputerWins,
        uint64 correctedScore,
        int64 correctedPoints
    ) external onlyDisputeResolver {
        ScoreProposal storage p = _pending[popId];
        require(p.status == ProposalStatus.Disputed, "ScoreRegistry: not disputed");

        if (disputerWins) {
            p.status = ProposalStatus.Rejected;
            _proposals[p.id].status = ProposalStatus.Rejected;
            emit ProposalRejected(p.id, popId);

            if (correctedScore > 0 || correctedPoints != 0) {
                uint64 oldScore = _finalized[popId].score;
                _finalized[popId] = FinalizedScore({
                    score: correctedScore,
                    totalPoints: correctedPoints,
                    eventsRoot: p.eventsRoot,
                    sourceBlockHeight: p.sourceBlockHeight,
                    finalizedAt: uint64(block.number),
                    proposalId: p.id
                });
                emit ScoreCorrected(popId, oldScore, correctedScore);
            }
        } else {
            // Dispute failed — the original proposal stands.
            p.status = ProposalStatus.Finalized;
            _proposals[p.id].status = ProposalStatus.Finalized;
            _finalized[popId] = FinalizedScore({
                score: p.score,
                totalPoints: p.totalPoints,
                eventsRoot: p.eventsRoot,
                sourceBlockHeight: p.sourceBlockHeight,
                finalizedAt: uint64(block.number),
                proposalId: p.id
            });
            emit ScoreFinalized(p.id, popId, p.score, uint64(block.number));
        }

        delete _pending[popId];
    }

    // ─────────────────────── Views ───────────────────────

    function getScore(bytes32 popId) external view returns (uint64 score, uint64 updatedAt) {
        FinalizedScore storage s = _finalized[popId];
        return (s.score, s.finalizedAt);
    }

    function getFullScore(bytes32 popId) external view returns (FinalizedScore memory) {
        return _finalized[popId];
    }

    function getPendingProposal(bytes32 popId) external view returns (ScoreProposal memory) {
        return _pending[popId];
    }

    function getProposal(uint64 proposalId) external view returns (ScoreProposal memory) {
        return _proposals[proposalId];
    }

    /// @notice Convenience: is a proposal eligible for finalize()?
    function canFinalize(bytes32 popId) external view returns (bool) {
        ScoreProposal storage p = _pending[popId];
        return
            p.status == ProposalStatus.Pending &&
            block.number >= p.proposedAt + CHALLENGE_WINDOW;
    }

    /// @notice Compute the canonical score from a points total.
    ///         Exposed so clients (UI, dispute path) agree on the mapping.
    function computeScore(int64 totalPoints) external pure returns (uint64) {
        return ScoreMath.computeScore(totalPoints);
    }
}

contracts/StakingVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IPointsLedger} from "./interfaces/IPointsLedger.sol";
import {IStakingVault} from "./interfaces/IStakingVault.sol";
import {PopId} from "./lib/PopId.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address) external view returns (uint256);
}

/// @title StakingVault
/// @notice Holds stablecoin deposits from users. Entry gate to the
///         PolkaCredit system.
/// @dev    popId is derived directly from msg.sender via PopId.fromAddress.
///         See lib/PopId.sol for the rationale.
contract StakingVault is IStakingVault {
    using PopId for address;

    /// @notice Minimum stake: $50 in an 18-decimals stablecoin.
    uint128 public constant MINIMUM_STAKE = 50 ether;

    /// @notice Lock duration ~6 months at 12s/block.
    uint64 public constant LOCK_DURATION = 129600;

    /// @notice Points granted on initial stake.
    uint64 public constant STAKE_DEPOSIT_POINTS = 10;

    IERC20 public immutable stablecoin;
    IPointsLedger public immutable pointsLedger;

    address public admin;
    address public vouchRegistry;
    /// @notice Non-reentrancy guard.
    uint256 private _locked = 1;

    mapping(bytes32 => StakeRecord) private _stakes;

    event Staked(bytes32 indexed popId, uint128 amount, uint64 stakedAt);
    event Unstaked(bytes32 indexed popId, uint128 amount, uint64 unstakedAt);
    event VouchRegistrySet(address indexed vouchRegistry);

    modifier onlyAdmin() {
        require(msg.sender == admin, "StakingVault: not admin");
        _;
    }

    modifier onlyVouchRegistry() {
        require(msg.sender == vouchRegistry, "StakingVault: not vouch registry");
        _;
    }

    modifier nonReentrant() {
        require(_locked == 1, "StakingVault: reentrant");
        _locked = 2;
        _;
        _locked = 1;
    }

    constructor(address _admin, address _stablecoin, address _pointsLedger) {
        require(_admin != address(0), "StakingVault: zero admin");
        require(_stablecoin != address(0), "StakingVault: zero stable");
        require(_pointsLedger != address(0), "StakingVault: zero ledger");
        admin = _admin;
        stablecoin = IERC20(_stablecoin);
        pointsLedger = IPointsLedger(_pointsLedger);
    }

    function setVouchRegistry(address _vouchRegistry) external onlyAdmin {
        require(_vouchRegistry != address(0), "StakingVault: zero registry");
        vouchRegistry = _vouchRegistry;
        emit VouchRegistrySet(_vouchRegistry);
    }

    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "StakingVault: zero admin");
        admin = newAdmin;
    }

    // ─────────────────────── Stake / unstake ───────────────────────

    function stake(uint128 amount) external nonReentrant {
        bytes32 popId = msg.sender.fromAddress();
        require(amount >= MINIMUM_STAKE, "StakingVault: below minimum");
        require(_stakes[popId].amount == 0, "StakingVault: already staked");

        require(stablecoin.transferFrom(msg.sender, address(this), amount), "StakingVault: transfer failed");

        _stakes[popId] = StakeRecord({
            amount: amount,
            stakedAt: uint64(block.number),
            lockUntil: uint64(block.number) + LOCK_DURATION,
            isLocked: false
        });

        pointsLedger.mintPoints(popId, STAKE_DEPOSIT_POINTS, "stake_deposit");

        emit Staked(popId, amount, uint64(block.number));
    }

    function unstake() external nonReentrant {
        bytes32 popId = msg.sender.fromAddress();

        StakeRecord memory s = _stakes[popId];
        require(s.amount > 0, "StakingVault: no stake");
        require(block.number >= s.lockUntil, "StakingVault: still locked");
        require(!s.isLocked, "StakingVault: active vouches");

        delete _stakes[popId];
        require(stablecoin.transfer(msg.sender, s.amount), "StakingVault: transfer failed");

        emit Unstaked(popId, s.amount, uint64(block.number));
    }

    // ─────────────────────── Lock controls (VouchRegistry) ───────────────────────

    function extendLock(bytes32 popId) external onlyVouchRegistry {
        require(_stakes[popId].amount > 0, "StakingVault: no stake");
        _stakes[popId].isLocked = true;
    }

    function releaseLock(bytes32 popId) external onlyVouchRegistry {
        _stakes[popId].isLocked = false;
    }

    // ─────────────────────── Views ───────────────────────

    function getStake(bytes32 popId) external view returns (StakeRecord memory) {
        return _stakes[popId];
    }

    function hasActiveStake(bytes32 popId) external view returns (bool) {
        return _stakes[popId].amount > 0;
    }
}

contracts/VouchRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IPointsLedger} from "./interfaces/IPointsLedger.sol";
import {IStakingVault} from "./interfaces/IStakingVault.sol";
import {PopId} from "./lib/PopId.sol";

/// @title VouchRegistry
/// @notice Manages vouch relationships between stakers. popId is derived
///         directly from msg.sender via PopId.fromAddress (see lib/PopId.sol).
contract VouchRegistry {
    using PopId for address;

    enum VouchStatus {
        None,
        Active,
        Succeeded,
        Failed,
        Defaulted
    }

    struct VouchRecord {
        uint64 id;
        bytes32 voucher;
        bytes32 vouchee;
        uint64 pointsLocked;
        uint64 createdAt;
        uint64 expiresAt;
        VouchStatus status;
    }

    // ─── Constants (from spec §2.2) ───
    uint64 public constant VOUCH_WINDOW = 129600; // ~6 months in 12s blocks
    uint64 public constant POINTS_TO_LOCK = 20;
    uint8 public constant MAX_VOUCHES_PER_MONTH = 3;
    uint64 public constant MIN_VOUCHER_SCORE = 50;
    uint64 public constant VOUCHEE_THRESHOLD = 30;
    uint64 public constant VOUCHER_SUCCESS_REWARD = 5;
    uint64 public constant VOUCHER_DEFAULT_PENALTY = 50;

    /// @notice ~1 month in 12s blocks, used for monthly vouch cap.
    uint64 public constant BLOCKS_PER_MONTH = 216000;

    IPointsLedger public immutable pointsLedger;
    IStakingVault public immutable stakingVault;

    address public admin;
    address public defaultReporter; // indexer or governance

    uint64 public nextVouchId = 1;

    mapping(uint64 => VouchRecord) private _vouches;
    mapping(bytes32 => uint64[]) public voucherIndex;
    mapping(bytes32 => uint64[]) public voucheeIndex;
    mapping(bytes32 => uint64) public activeVouchCount; // voucher popId -> count
    /// @notice Monthly vouch count per voucher. Keyed by (popId, monthBucket).
    mapping(bytes32 => mapping(uint64 => uint8)) public monthlyVouchCount;

    event VouchCreated(
        uint64 indexed vouchId, bytes32 indexed voucher, bytes32 indexed vouchee, uint64 createdAt, uint64 expiresAt
    );
    event VouchSucceeded(uint64 indexed vouchId);
    event VouchFailed(uint64 indexed vouchId);
    event VouchDefaulted(uint64 indexed vouchId, bytes32 indexed vouchee);
    event DefaultReporterSet(address indexed reporter);

    modifier onlyAdmin() {
        require(msg.sender == admin, "VouchRegistry: not admin");
        _;
    }

    constructor(address _admin, address _pointsLedger, address _stakingVault) {
        require(_admin != address(0), "VouchRegistry: zero admin");
        admin = _admin;
        pointsLedger = IPointsLedger(_pointsLedger);
        stakingVault = IStakingVault(_stakingVault);
    }

    function setDefaultReporter(address reporter) external onlyAdmin {
        require(reporter != address(0), "VouchRegistry: zero reporter");
        defaultReporter = reporter;
        emit DefaultReporterSet(reporter);
    }

    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "VouchRegistry: zero admin");
        admin = newAdmin;
    }

    // ─────────────────────── Core flows ───────────────────────

    function vouch(bytes32 voucheePopId) external returns (uint64) {
        bytes32 voucherPopId = msg.sender.fromAddress();
        require(voucheePopId != bytes32(0), "VouchRegistry: vouchee zero");
        require(voucherPopId != voucheePopId, "VouchRegistry: self vouch");

        require(stakingVault.hasActiveStake(voucherPopId), "VouchRegistry: voucher no stake");
        require(stakingVault.hasActiveStake(voucheePopId), "VouchRegistry: vouchee no stake");

        uint64 monthBucket = uint64(block.number) / BLOCKS_PER_MONTH;
        require(monthlyVouchCount[voucherPopId][monthBucket] < MAX_VOUCHES_PER_MONTH, "VouchRegistry: monthly cap");

        IPointsLedger.PointsBalance memory bal = pointsLedger.getBalance(voucherPopId);
        require(bal.total >= int64(MIN_VOUCHER_SCORE), "VouchRegistry: below min score");
        require(bal.available >= int64(POINTS_TO_LOCK), "VouchRegistry: insufficient available");

        uint64 vouchId = nextVouchId++;
        uint64 createdAt = uint64(block.number);
        uint64 expiresAt = createdAt + VOUCH_WINDOW;

        _vouches[vouchId] = VouchRecord({
            id: vouchId,
            voucher: voucherPopId,
            vouchee: voucheePopId,
            pointsLocked: POINTS_TO_LOCK,
            createdAt: createdAt,
            expiresAt: expiresAt,
            status: VouchStatus.Active
        });

        voucherIndex[voucherPopId].push(vouchId);
        voucheeIndex[voucheePopId].push(vouchId);
        activeVouchCount[voucherPopId] += 1;
        monthlyVouchCount[voucherPopId][monthBucket] += 1;

        pointsLedger.lockPoints(voucherPopId, POINTS_TO_LOCK, vouchId);
        stakingVault.extendLock(voucherPopId);

        emit VouchCreated(vouchId, voucherPopId, voucheePopId, createdAt, expiresAt);
        return vouchId;
    }

    function resolveVouch(uint64 vouchId) external {
        VouchRecord storage v = _vouches[vouchId];
        require(v.status == VouchStatus.Active, "VouchRegistry: not active");
        require(block.number >= v.expiresAt, "VouchRegistry: window open");

        uint64 earned = pointsLedger.getPointsEarnedInWindow(v.vouchee, v.createdAt, v.expiresAt);

        if (earned >= VOUCHEE_THRESHOLD) {
            v.status = VouchStatus.Succeeded;
            pointsLedger.unlockPoints(v.voucher, v.pointsLocked, vouchId);
            pointsLedger.mintPoints(v.voucher, VOUCHER_SUCCESS_REWARD, "vouch_success");
            pointsLedger.mintPoints(v.vouchee, 2, "vouched_for");
            emit VouchSucceeded(vouchId);
        } else {
            v.status = VouchStatus.Failed;
            pointsLedger.burnLockedPoints(v.voucher, v.pointsLocked, vouchId);
            if (earned > 0) {
                pointsLedger.burnPoints(v.vouchee, earned / 2, "vouch_halve");
            }
            emit VouchFailed(vouchId);
        }

        _decActive(v.voucher);
    }

    /// @notice Report that the vouchee defaulted on an external protocol while
    /// a vouch was active. Permissioned to the Indexer or governance.
    function reportDefault(uint64 vouchId) external {
        require(msg.sender == defaultReporter || msg.sender == admin, "VouchRegistry: not reporter");
        VouchRecord storage v = _vouches[vouchId];
        require(v.status == VouchStatus.Active, "VouchRegistry: not active");

        v.status = VouchStatus.Defaulted;

        // Voucher penalty: burn 50 locked points (burnLockedPoints caps the locked
        // portion and burns the rest from available).
        pointsLedger.burnLockedPoints(v.voucher, VOUCHER_DEFAULT_PENALTY, vouchId);

        // Vouchee reset: zero out current positive balance by burning it.
        IPointsLedger.PointsBalance memory vb = pointsLedger.getBalance(v.vouchee);
        if (vb.total > 0) {
            pointsLedger.burnPoints(v.vouchee, uint64(int64(vb.total)), "default");
        }

        emit VouchDefaulted(vouchId, v.vouchee);
        _decActive(v.voucher);
    }

    function _decActive(bytes32 voucher) internal {
        if (activeVouchCount[voucher] > 0) {
            activeVouchCount[voucher] -= 1;
        }
        if (activeVouchCount[voucher] == 0) {
            stakingVault.releaseLock(voucher);
        }
    }

    // ─────────────────────── Views ───────────────────────

    function getVouch(uint64 vouchId) external view returns (VouchRecord memory) {
        return _vouches[vouchId];
    }

    function vouchesMadeBy(bytes32 popId) external view returns (uint64[] memory) {
        return voucherIndex[popId];
    }

    function vouchesReceivedBy(bytes32 popId) external view returns (uint64[] memory) {
        return voucheeIndex[popId];
    }
}

contracts/WalletRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {PopId} from "./lib/PopId.sol";

/// @title WalletRegistry
/// @notice Links external-chain wallet addresses (e.g. SS58 accounts on the
///         Polkadot relay chain) to the caller's popId, so the indexer can
///         attribute OpenGov votes back to the right identity.
/// @dev    popId is derived from msg.sender via PopId.fromAddress. `signature`
///         is stored on-chain and cryptographically validated off-chain by the
///         indexer; links whose signatures fail to verify are ignored.
contract WalletRegistry {
    using PopId for address;

    struct WalletLink {
        uint32 chainId; // parachain ID, 0 = relay chain
        bytes32 addressBytes; // SS58 public key (32 bytes) or padded EVM addr
        uint64 registeredAt;
        bool isActive;
        bytes signature; // proof of control over the external key
    }

    address public admin;

    mapping(bytes32 => WalletLink[]) private _linksByPop;
    /// @notice Reverse lookup (chainId, addressBytes) → popId.
    mapping(uint32 => mapping(bytes32 => bytes32)) public walletToPopId;

    event WalletRegistered(bytes32 indexed popId, uint32 indexed chainId, bytes32 addressBytes);
    event WalletRevoked(bytes32 indexed popId, uint32 indexed chainId, bytes32 addressBytes);

    modifier onlyAdmin() {
        require(msg.sender == admin, "WalletRegistry: not admin");
        _;
    }

    constructor(address _admin) {
        require(_admin != address(0), "WalletRegistry: zero admin");
        admin = _admin;
    }

    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "WalletRegistry: zero admin");
        admin = newAdmin;
    }

    /// @notice Register an external-chain wallet as belonging to the caller.
    ///         `signature` must be a signature over
    ///         keccak256("PolkaCredit link" || popId || chainId || addressBytes)
    ///         produced by the external key.
    function registerWallet(uint32 chainId, bytes32 addressBytes, bytes calldata signature) external {
        bytes32 popId = msg.sender.fromAddress();
        require(addressBytes != bytes32(0), "WalletRegistry: zero addr");
        require(walletToPopId[chainId][addressBytes] == bytes32(0), "WalletRegistry: already linked");

        _linksByPop[popId].push(
            WalletLink({
                chainId: chainId,
                addressBytes: addressBytes,
                registeredAt: uint64(block.number),
                isActive: true,
                signature: signature
            })
        );
        walletToPopId[chainId][addressBytes] = popId;
        emit WalletRegistered(popId, chainId, addressBytes);
    }

    function revokeWallet(uint32 chainId, bytes32 addressBytes) external {
        bytes32 popId = msg.sender.fromAddress();
        require(walletToPopId[chainId][addressBytes] == popId, "WalletRegistry: not your link");

        WalletLink[] storage links = _linksByPop[popId];
        for (uint256 i = 0; i < links.length; i++) {
            if (links[i].chainId == chainId && links[i].addressBytes == addressBytes) {
                links[i].isActive = false;
                break;
            }
        }
        delete walletToPopId[chainId][addressBytes];
        emit WalletRevoked(popId, chainId, addressBytes);
    }

    // ─────────────────────── Views ───────────────────────

    function getLinks(bytes32 popId) external view returns (WalletLink[] memory) {
        return _linksByPop[popId];
    }

    function popIdForWallet(uint32 chainId, bytes32 addressBytes) external view returns (bytes32) {
        return walletToPopId[chainId][addressBytes];
    }

    /// @notice Hash the caller must sign off-chain for registerWallet.
    function linkMessage(bytes32 popId, uint32 chainId, bytes32 addressBytes) external pure returns (bytes32) {
        return keccak256(abi.encodePacked("PolkaCredit link", popId, chainId, addressBytes));
    }
}

